    case tightFilterPalette:
      assert(buflen >= 1);

      palSize = *bufptr + 1;
      bufptr += 1;
      buflen -= 1;

      if (pf.is888()) {
        size_t len = palSize * 3;
        rdr::U8Array tightPalette(len);

        assert(buflen >= len);

        memcpy(tightPalette.buf, bufptr, len);
        bufptr += len;
        buflen -= len;

